$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Dni przechowywania statystyk połączeń';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Wiersze starsze niż ta wartość zostaną usunięte z connections, connections_source i connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Podaj liczbę dni, przez które mają być przechowywane surowe statystyki odwiedzin PrestaShop. Przykład: 60 oznacza zachowanie ostatnich 60 dni i usunięcie starszych rekordów z ps_connections, ps_connections_source i ps_connections_page. Nie ustawiaj 1, jeśli nie masz pewności, że nie potrzebujesz ostatnich statystyk.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Rozmiar partii';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Maksymalna liczba połączeń przetwarzanych w jednej partii.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Podaj, ile głównych rekordów połączeń może być przetworzonych w jednej wewnętrznej partii. Mniejsze wartości są bezpieczniejsze na słabym hostingu, ale wymagają więcej uruchomień cron. Większe wartości czyszczą szybciej, ale mogą dłużej blokować bazę danych. Zalecany start: 1000 do 5000; zwiększaj dopiero po testach czasu działania.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maksymalna liczba partii na uruchomienie';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Ogranicza ilość pracy jednego uruchomienia cron.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Podaj, ile partii może działać podczas jednego uruchomienia cron. Łączna możliwa liczba usuniętych rekordów to około Rozmiar partii razy Maksymalna liczba partii. Przykład: 5000 i 10 oznacza do około 50000 rekordów w jednym uruchomieniu cron. Zmniejsz, jeśli sklep zwalnia podczas czyszczenia.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Wyczyść ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Czyści cache bloku wyszukiwania fasetowego/layered za pomocą TRUNCATE TABLE. Tabela jest odtwarzana jako pusta przez MySQL/MariaDB.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Włącz tylko wtedy, gdy ps_layered_filter_block nadmiernie rośnie lub zawiera nieaktualny cache wyszukiwania fasetowego. Nie usuwa produktów, kategorii ani indeksu cen layered. Po czyszczeniu PrestaShop lub moduł wyszukiwania fasetowego może odbudować cache.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agreguj statystyki źródeł ruchu przed usunięciem';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Zapisuje dzienne podsumowane statystyki źródeł ruchu przed usunięciem surowych wierszy.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Po włączeniu moduł zapisuje małe dzienne podsumowanie przed usunięciem surowych statystyk PrestaShop. Przechowuje liczniki odwiedzin, odsłon, domenę źródłową i wartości UTM. Nie zapisuje adresów IP, pełnych URL referrer ani ciągów user-agent. Wyłącz, jeśli chcesz tylko usuwać dane.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Dni przechowywania statystyk zagregowanych';
