$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a1a47524ffa9c839887703df1fbe70a3'] = 'Wyczyść ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_924684322fe68e56ef9205e7f480f598'] = 'Czyści cache bloku wyszukiwania fasetowego/layered za pomocą TRUNCATE TABLE. Tabela jest odtwarzana jako pusta przez MySQL/MariaDB.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Włącz tylko wtedy, gdy ps_layered_filter_block nadmiernie rośnie lub zawiera nieaktualny cache wyszukiwania fasetowego. Nie usuwa produktów, kategorii ani indeksu cen layered. Po czyszczeniu PrestaShop lub moduł wyszukiwania fasetowego może odbudować cache.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agreguj statystyki źródeł ruchu przed usunięciem';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Zapisuje dzienne podsumowane statystyki źródeł ruchu przed usunięciem surowych wierszy.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Po włączeniu moduł zapisuje małe dzienne podsumowanie przed usunięciem surowych statystyk PrestaShop. Przechowuje liczniki odwiedzin, odsłon, domenę źródłową i wartości UTM. Nie zapisuje adresów IP, pełnych URL referrer ani ciągów user-agent. Wyłącz, jeśli chcesz tylko usuwać dane.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Dni przechowywania statystyk zagregowanych';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Jak długo ma być przechowywana mała dzienna tabela podsumowań.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Podaj, ile dni zagregowane podsumowania źródeł ruchu mają pozostać w tabeli modułu. Przykład: 730 przechowuje około dwa lata dziennych podsumowań. To ustawienie dotyczy tylko ps_jooim_dbcleaner_traffic_daily, nie oryginalnych tabel statystyk PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Limit starej blokady w sekundach';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Ochrona przed równoczesnym działaniem dwóch procesów czyszczenia.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Podaj liczbę sekund, po których niedokończona blokada czyszczenia jest uznawana za porzuconą. Chroni to bazę przed dwoma jednoczesnymi uruchomieniami cron. Zalecane: 7200. Zmniejszaj tylko jeśli cron zawsze kończy szybko.';
